import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./login.css"
import Mainweatherpage from "./mainweatherpage";
import { UseStore } from "./store";
function Login() {
    const navigate = useNavigate()
    let [nameinput, changenameinput] = useState("")
    let [passwordinput, changepasswordinput] = useState("")
    function getinputn(e) {
        changenameinput(e.target.value)
    }
    function getinputp(e) {
        changepasswordinput(e.target.value)
    }
    async function func1() {  
        await fetch("http://localhost:5000/login", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({nameforlog: nameinput, passwordforlog: passwordinput})
        }
        )
    }
    return<>
<div className="login-card">
  <h1>Log into an account</h1>

  <label>Username</label>
  <input value={nameinput} onChange={(e) => getinputn(e)} />

  <label>Password</label>
  <input value={passwordinput} onChange={(e) => getinputp(e)} type="password" />

  <button onClick={() => func1()}>Login</button>
</div>
    </>
}
export default Login
